(window.webpackJsonp=window.webpackJsonp||[]).push([[245],{872:function(n,e){n.exports="\x3c!-- \ntitle: 40-TypeScript\nsort: \n--\x3e \n\n==rwer==\n\n> 使用TypeScrip开发\n\n```bash\nyarn add typescript\nyarn tsc filename.ts --watch\n```\n\n## 变量\n\n```ts\nlet a: string = 'abc';\nlet b: number = 1;\nlet c: string[] = ['a', 'b', 'c'];\nlet d: number[] = [1, 2, 3];\nlet e: boolean = true;\nlet f: [number, string] = [1, 'hello'];\nlet g: any = 1;\nlet h: any = 'a';\nfunction fun(): void {\n    alert(1);\n}\nlet hello = (name: string): string => `Hello ${name}`\nlet obj = { a: 1, b: 1 }\nlet add = ({ a, b }: { a: number, b: number }) => { a + b };\n```\n\n## 类\n\n```ts\nclass Person {\n    name: string;\n    constructor(name: string) {\n        this.name = name;\n    }\n    greet() {\n        return `${this.name} say: hi~`\n    }\n\n}\n\nlet fzf = new Person('fzf');\nconsole.log(fzf.greet())\n// fzf say: hi~\n\n// 继承\nclass Student extends Person {\n    private major: string;\n    constructor(name: string, major: string) {\n        super(name)\n        this.major = major;\n    }\n    studentGreet() {\n        return `${this.major} manjor's ${this.name} say hi~.`\n    }\n}\n\nlet fzf = new Student('fzf', 'anime')\nconsole.log(fzf.studentGreet()) \n// anime manjor's fzf say hi~.\n```\n\n"}}]);